        isLastAssistant && latestReasoning?.content
          ? { content: latestReasoning.content, duration: latestReasoning.durationMs ?? 0 }
          : undefined;
      return {
        key: m.id,
        from: m.role as "user" | "assistant",
        planPreviews: m.planPreviews,
        sources,
        reasoning,
        versions: [{ id: m.id, content: m.content }],
      };
    });
}

